public class Main {
    public static void main(String[] args) {

        // Student data
        String name  = "Priya Verma";
        int    marks = 88;
        double gpa   = 3.75;

        /* Print the report header using print (no newline)
           then println for the final newline. */
        System.out.print("=== ");
        System.out.print("Student Report");
        System.out.println(" ===");

        // Use println for each labelled field
        System.out.println("Name  : " + name);
        System.out.println("Marks : " + marks);

        // Use printf for formatted decimal output
        System.out.printf("GPA   : %.2f%n", gpa);
        System.out.printf("Grade : %s%n", marks >= 90 ? "A" : "B");
    }
}

