exercise.solutionCode:
public class Main {
    public static void main(String[] args) {
        String item  = "Laptop";
        int    qty   = 2;
        double price = 45000.0;

        System.out.print("--- ");
        System.out.println("Invoice ---");
        System.out.println("Item     : " + item);
        System.out.println("Quantity : " + qty);
        System.out.printf("Total    : %.2f%n", qty * price);
    }
}
